To achieve this, the method will split the input string into words, check if each word is in the exception list, and apply title case accordingly. The first word will always be capitalized regardless of its presence in the exception list. The rest of the words will be capitalized unless they are in the exception list.

Here is a sample implementation:

public class TitleCaseConverter {
    private static final Set<String> EXCEPTIONS = Set.of("of", "the", "is", "and");

    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        String[] words = input.split("\\s+");
        StringBuilder result = new StringBuilder();
        boolean firstWord = true;

        for (String word : words) {
            String lowerWord = word.toLowerCase();
            if (firstWord) {
                result.append(capitalize(lowerWord));
                firstWord = false;
            } else {
                if (!EXCEPTIONS.contains(lowerWord)) {
                    result.append(" ").append(capitalize(lowerWord));
                } else {
                    result.append(" ").append(lowerWord);
                }
            }
        }

        return result.toString();
    }

    private static String capitalize(String word) {
        if (word == null || word.isEmpty()) {
            return word;
        }
        return word.substring(0, 1).toUpperCase() + word.substring(1).toLowerCase();
    }

    public static void main(String[] args) {
        String input = "this is the string to be converted";
        String output = toTitleCase(input);
        System.out.println(output);
    }
}

